#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 1000

int maximalCrosses(int n, char **A) {
    int **B = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        B[i] = (int *)malloc(n * sizeof(int));
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (A[i][j] == '.') {
                B[i][j] = 0;
            } else {
                int horizontal = 0, vertical = 0, mainDiagonal = 0, antiDiagonal = 0;
                // Calculate horizontal
                for (int k = j; k >= 0 && A[i][k] == 'X'; k--) {
                    horizontal++;
                }
                for (int k = j + 1; k < n && A[i][k] == 'X'; k++) {
                    horizontal++;
                }
                // Calculate vertical
                for (int k = i; k >= 0 && A[k][j] == 'X'; k--) {
                    vertical++;
                }
                for (int k = i + 1; k < n && A[k][j] == 'X'; k++) {
                    vertical++;
                }
                // Calculate main diagonal
                for (int k = i, l = j; k >= 0 && l >= 0 && A[k][l] == 'X'; k--, l--) {
                    mainDiagonal++;
                }
                for (int k = i + 1, l = j + 1; k < n && l < n && A[k][l] == 'X'; k++, l++) {
                    mainDiagonal++;
                }
                // Calculate anti-diagonal
                for (int k = i, l = j; k >= 0 && l < n && A[k][l] == 'X'; k--, l++) {
                    antiDiagonal++;
                }
                for (int k = i + 1, l = j - 1; k < n && l >= 0 && A[k][l] == 'X'; k++, l--) {
                    antiDiagonal++;
                }
                B[i][j] = (horizontal > vertical) ? ((horizontal > mainDiagonal) ? ((horizontal > antiDiagonal) ? horizontal : antiDiagonal) : ((mainDiagonal > antiDiagonal) ? mainDiagonal : antiDiagonal)) : ((vertical > mainDiagonal) ? ((vertical > antiDiagonal) ? vertical : antiDiagonal) : ((mainDiagonal > antiDiagonal) ? mainDiagonal : antiDiagonal));
            }
        }
    }
    // Print the result
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            printf("%d ", B[i][j]);
        }
        printf("\n");
    }
    return 0;
}

int main() {
    int n;
    scanf("%d", &n);
    char **A = (char **)malloc(n * sizeof(char *));
    for (int i = 0; i < n; i++) {
        A[i] = (char *)malloc((n + 1) * sizeof(char));
        scanf("%s", A[i]);
    }
    maximalCrosses(n, A);
    return 0;
}

