        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (A[i][j] == '.') {
                    B[i][j] = 0;
                } else {
                    int horizontal = 0, vertical = 0, mainDiagonal = 0, antiDiagonal = 0;
                    // Calculate horizontal
                    for (int k = j; k >= 0 && A[i][k] == 'X'; k--) {
                        horizontal++;
                    }
                    for (int k = j + 1; k < n && A[i][k] == 'X'; k++) {
                        horizontal++;
                    }
                    // Calculate vertical
                    for (int k = i; k >= 0 && A[k][j] == 'X'; k--) {
                        vertical++;
                    }
                    for (int k = i + 1; k < n && A[k][j] == 'X'; k++) {
                        vertical++;
                    }
                    // Calculate main diagonal
                    for (int k = i, l = j; k >= 0 && l >= 0 && A[k][l] == 'X'; k--, l--) {
                        mainDiagonal++;
                    }
                    for (int k = i + 1, l = j + 1; k < n && l < n && A[k][l] == 'X'; k++, l++) {
                        mainDiagonal++;
                    }
                    // Calculate anti-diagonal
                    for (int k = i, l = j; k >= 0 && l < n && A[k][l] == 'X'; k--, l++) {
                        antiDiagonal++;
                    }
                    for (int k = i + 1, l = j - 1; k < n && l >= 0 && A[k][l] == 'X'; k++, l--) {
                        antiDiagonal++;
                    }
                    B[i][j] = Math.max(Math.max(horizontal, vertical), Math.max(mainDiagonal, antiDiagonal));
                }
            }
        }
        // Print the result
