        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        char[][] A = new char[n][n];
        for (int i = 0; i < n; i++) {
            String s = sc.next();
            for (int j = 0; j < n; j++) {
                A[i][j] = s.charAt(j);
            }
        }
        maximalCrosses(n, A);
    }
